import{C as t,o,c as n,a5 as a,E as l}from"./chunks/framework.CW28V7p_.js";const c=JSON.parse('{"title":"1. Proof of History (PoH)","description":"","frontmatter":{},"headers":[],"relativePath":"module-4/1-poh.md","filePath":"module-4/1-poh.md","lastUpdated":1780937944000}'),r={name:"module-4/1-poh.md"},k=Object.assign(r,{setup(h){const e={id:"m4-1-poh",title:"🧠 Mini-check: Proof of History",intro:"3 питання — PoH fundamentals.",questions:[{type:"explain",q:"Поясни своїми словами що таке PoH і чому Solana її потребує.",ideal:`PoH (Proof of History) — це децентралізований "годинник", який доводить що passing time через recursive SHA-256 hashing. Validator continuously обчислює hash(previous_hash) у loop, кожна iteration triggers "tick". Скільки ticks = скільки часу пройшло (з deterministic перерахунком per ticks per second).

Чому Solana потребує:

1. Без trusted clock — нема способу validators agree про порядок подій. PoH дає cryptographically verifiable timeline без trust.

2. Enables 400ms slots: leader може швидко вкладати TXs у "поточне" time window (current PoH tick range), без чекати global gossip про "котра година".

3. Permits fast Tower BFT consensus: validators використовують PoH timestamps щоб verify когда vote was issued, прискорюючи tower computation.

4. Reduces network overhead: не треба broadcast "сurrent time" з кожним message — PoH sequence sами self-проявляє time.

Аналогія: SHA-256 hashing як stopwatch — кожен click того ж самого хімічного механізму doves одиниця часу пройшла, тому що SHA є computationally expensive (потрібен real CPU work). Не можна fake "I did 1000 hashes" без реально їх обчислення.`,explanation:"Ключове: cryptographic clock без trust, enabler fast consensus. Якщо описала hashing loop + чому це matter — повна відповідь."},{type:"mcq",q:"Що з цього вірно про PoH? (обери всі)",options:["PoH тільки leader обчислює, не cluster","PoH не consensus per se — це timestamping mechanism","PoH ticks deterministic — different validators verifying same sequence reach same conclusions","PoH замінює Tower BFT як voting consensus"],correct:[0,1,2],explanation:"PoH — це clock, не voting consensus (Tower BFT робить voting). Тільки current leader generates PoH. Other validators verify sequence. Tower BFT та PoH працюють разом. Module 4.1."},{type:"mcq",q:'Що значить "tick" у PoH context?',options:["Single iteration hash(prev_hash) → next_hash","Marker через які passing time можна measure","Group of ~12,500 hashes that produce one PoH counter increment","Vote signal до cluster"],correct:[0,1,2],explanation:"Tick це basic time unit у PoH. На mainnet 1 tick = ~12,500 hashes (~6.25 ticks per slot). Не vote (це Tower BFT). Module 4.1."}]};return(p,s)=>{const i=t("Quiz");return o(),n("div",null,[s[0]||(s[0]=a("",54)),l(i,{data:e}),s[1]||(s[1]=a("",6))])}}});export{c as __pageData,k as default};
